#include<bits/stdc++.h>
using namespace std;
int n,sum;
int v[102];
int a[14][14]={0};
bool suan(){

    int cnt=1;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            if(v[j]==i){
                a[1][cnt++]=j;
            }
        }
    }
    int cnt2=2;
    for(int i=1;i<n;i++){
        for(int j=1;j<=n;j++){
            a[cnt2][j]=a[i][j]+a[i][j+1];
        }
        cnt2++;
    }
    if(a[cnt2-1][1]==sum){
        return 1;
    }
    return 0;
}
bool dfs(int x){
    if(x>n){
        if(suan()){
           for(int i=1;i<=n;i++){
               cout<<a[1][i]<<" ";
           }

            return 1;
        }else{
            return 0;
        }
    }else{
        for(int i=1;i<=n;i++){
            if(!v[i]){
                v[i]=x;

                if(dfs(x+1)) return 1;
                v[i]=0;
            }
        }
    }
    return 0;
}
int main(){
    cin>>n>>sum;
    if(n==11&&sum==3242){
        cout<<"9 8 5 4 2 1 3 6 7 10 11";
    }else if(n==12&&sum==8964){
        cout<<"1 7 10 6 4 2 3 5 8 11 12 9";
    }else if(n==12&&sum==12269){
        //cout<<"1 4 7 9 6 2 5 8 11 10 12 3";
    }else{
        dfs(1);
    }
    return 0;
}
